// Normalize personnummer to 12 digits and preserve checkin_id/tag/slug
const body = $json.body ?? $json;
let pnrRaw = body.personnummer ?? null;

if (!pnrRaw) {
  throw new Error('Personnummer krävs för registrering');
}

let pnr = pnrRaw.toString().replace(/\D/g, '');

if (pnr.length < 10) {
  throw new Error('Ogiltigt personnummer-format');
}

// Convert 10-digit to 12-digit
if (pnr.length === 10) {
  const yy = parseInt(pnr.slice(0, 2), 10);
  const prefix = yy > 30 ? '19' : '20';
  pnr = prefix + pnr;
}

const email = body.email || '';
const phone = (body.telephone || body.telefon || '').replace(/[\s-]/g, '');
const nick = body.nick || body.tag || null;
const discord = body.discord || null;

const tag = (body.tag || '').toLowerCase().trim();
const slug = body.slug || '';
const checkin_id = body.checkin_id || '';

const today = new Date().toISOString().split('T')[0];

return [{ json: {
  pnr,
  email,
  phone,
  nick,
  discord,
  renewed: today,
  tag,
  slug,
  checkin_id,
}}];

// Parse eBas submit_member_with_lookup response
const response = $json;
const input = $('Normalize Input').first().json;
const tag = input.tag || '';
const slug = input.slug || '';
const checkin_id = input.checkin_id || '';

if (response.stored_member === true && response.request_result === 'success') {
  return [{
    json: {
      success: true,
      registered: true,
      message: 'Medlem registrerad i Sverok',
      tag,
      slug,
      checkin_id,
    }
  }];
}

if (response.member_errors) {
  const errors = Object.entries(response.member_errors)
    .map(([field, msgs]) => field + ': ' + msgs.join(', '))
    .join('; ');
  return [{
    json: {
      success: false,
      error: true,
      message: errors || 'Kunde inte registrera medlem',
      details: response.member_errors,
      tag,
      slug,
      checkin_id,
    }
  }];
}

return [{
  json: {
    success: false,
    error: true,
    message: response.request_result || 'Okänt fel',
    raw_response: response,
    tag,
    slug,
    checkin_id,
  }
}];

// Return success response
const parsed = $('Parse Response').first().json;
return [{ json: parsed }];

// Return error response
const parsed = $('Parse Response').first().json;
return [{ json: parsed }];
